// Basic rigidity check for a graph
class RigidityChecker {
  constructor() {
    this.EPSILON = 1e-10;
  }

  // Check if framework is infinitesimally rigid
  checkInfinitesimalRigidity(graph, positions) {
    const rigidityMatrix = this.buildRigidityMatrix(graph, positions);
    const rank = this.matrixRank(rigidityMatrix);
    const expectedRank = 2 * graph.vertices.length - 3;

    return {
      isRigid: rank >= expectedRank,
      rank: rank,
      expectedRank: expectedRank,
      rigidityMatrix: rigidityMatrix
    };
  }

  // Build rigidity matrix
  buildRigidityMatrix(graph, positions) {
    const edges = graph.edges;
    const vertices = graph.vertices;
    const m = edges.length;
    const n = vertices.length;

    // Rigidity matrix: m × 2n
    const matrix = Array(m).fill().map(() => Array(2 * n).fill(0));

    for (let i = 0; i < m; i++) {
      const [u, v] = edges[i];
      const pu = positions[u];
      const pv = positions[v];

      const dx = pu.x - pv.x;
      const dy = pu.y - pv.y;

      // Row for edge (u,v)
      matrix[i][2 * u] = dx;
      matrix[i][2 * u + 1] = dy;
      matrix[i][2 * v] = -dx;
      matrix[i][2 * v + 1] = -dy;
    }

    return matrix;
  }

  // Compute matrix rank using Gaussian elimination
  matrixRank(matrix) {
    const m = matrix.length;
    const n = matrix[0].length;
    const mat = matrix.map(row => [...row]); // Deep copy

    let rank = 0;
    let row = 0;

    for (let col = 0; col < n && row < m; col++) {
      // Find pivot
      let pivot = row;
      for (let i = row + 1; i < m; i++) {
        if (Math.abs(mat[i][col]) > Math.abs(mat[pivot][col])) {
          pivot = i;
        }
      }

      if (Math.abs(mat[pivot][col]) < this.EPSILON) {
        continue; // Skip this column
      }

      // Swap rows
      [mat[row], mat[pivot]] = [mat[pivot], mat[row]];

      // Eliminate below
      for (let i = row + 1; i < m; i++) {
        const factor = mat[i][col] / mat[row][col];
        for (let j = col; j < n; j++) {
          mat[i][j] -= factor * mat[row][j];
        }
      }

      rank++;
      row++;
    }

    return rank;
  }
}

