// Check Laman's conditions
class LamansTheoremChecker {
  checkLamanConditions(graph) {
    const n = graph.vertices.length;
    const m = graph.edges.length;

    const condition1 = m === 2 * n - 3;
    const condition2 = this.checkSubgraphCondition(graph);

    return {
      isGenericallyRigid: condition1 && condition2,
      condition1: {
        satisfied: condition1,
        description: `|E| = ${m}, 2|V| - 3 = ${2 * n - 3}`
      },
      condition2: {
        satisfied: condition2,
        description: condition2 ?
          "All subgraphs satisfy |E'| ≤ 2k - 3" :
          "Some subgraph violates the condition"
      }
    };
  }

  checkSubgraphCondition(graph) {
    const vertices = graph.vertices;
    const edges = graph.edges;

    // Check all non-empty subsets of vertices
    for (let k = 2; k <= vertices.length; k++) {
      const subsets = this.getSubsets(vertices, k);

      for (const subset of subsets) {
        const subgraphEdges = this.getInducedEdges(edges, subset);

        if (subgraphEdges.length > 2 * k - 3) {
          console.log(`Violating subgraph: ${subset.length} vertices, ${subgraphEdges.length} edges`);
          return false;
        }
      }
    }

    return true;
  }

  getSubsets(array, size) {
    const result = [];

    function generate(start, current) {
      if (current.length === size) {
        result.push([...current]);
        return;
      }

      for (let i = start; i < array.length; i++) {
        current.push(array[i]);
        generate(i + 1, current);
        current.pop();
      }
    }

    generate(0, []);
    return result;
  }

  getInducedEdges(edges, vertices) {
    const vertexSet = new Set(vertices);
    return edges.filter(([u, v]) =>
      vertexSet.has(u) && vertexSet.has(v)
    );
  }
}

// Example: Check if a graph is a Laman graph
const graph = {
  vertices: [0, 1, 2, 3],
  edges: [[0, 1], [1, 2], [2, 3], [3, 0], [0, 2]]
};

const checker = new LamansTheoremChecker();
const result = checker.checkLamanConditions(graph);
console.log(result.isGenericallyRigid ? "Laman graph" : "Not a Laman graph");

// Henneberg construction for Laman graphs
class HennebergConstructor {
  // Start with K3 (triangle)
  createBaseGraph() {
    return {
      vertices: [0, 1, 2],
      edges: [[0, 1], [1, 2], [2, 0]]
    };
  }

  // Henneberg Type I: Add vertex of degree 2
  henneberg1(graph, u, v) {
    const newVertex = graph.vertices.length;
    const newGraph = {
      vertices: [...graph.vertices, newVertex],
      edges: [...graph.edges, [u, newVertex], [v, newVertex]]
    };

    // Verify it's still a Laman graph
    const checker = new LamansTheoremChecker();
    const result = checker.checkLamanConditions(newGraph);

    if (!result.isGenericallyRigid) {
      throw new Error("Resulting graph is not a Laman graph");
    }

    return newGraph;
  }

  // Build a Laman graph step by step
  buildLamanGraph(steps) {
    let graph = this.createBaseGraph();
    const checker = new LamansTheoremChecker();

    for (const step of steps) {
      if (step.type === 'henneberg1') {
        graph = this.henneberg1(graph, step.u, step.v);
      }
    }

    return graph;
  }
}

// Example: Build a 4-vertex Laman graph
const constructor = new HennebergConstructor();
const graph = constructor.buildLamanGraph([
  { type: 'henneberg1', u: 0, v: 1 },  // Add vertex 3
  { type: 'henneberg1', u: 1, v: 2 }   // Add vertex 4
]);

console.log('Laman graph:', graph);

