// Rigidity visualization
class RigidityVisualizer {
  constructor(canvas) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d');
    this.vertices = [];
    this.edges = [];
    this.dragging = null;
  }

  drawGraph() {
    const ctx = this.ctx;
    ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

    // Draw edges
    ctx.strokeStyle = '#3b82f6';
    ctx.lineWidth = 2;
    for (const [u, v] of this.edges) {
      const pu = this.vertices[u];
      const pv = this.vertices[v];
      ctx.beginPath();
      ctx.moveTo(pu.x, pu.y);
      ctx.lineTo(pv.x, pv.y);
      ctx.stroke();
    }

    // Draw vertices
    ctx.fillStyle = '#22c55e';
    for (const v of this.vertices) {
      ctx.beginPath();
      ctx.arc(v.x, v.y, 8, 0, 2 * Math.PI);
      ctx.fill();
    }
  }

  // Check if dragging preserves edge lengths
  checkRigidity(movedVertex, newPosition) {
    for (const [u, v] of this.edges) {
      if (u === movedVertex || v === movedVertex) {
        const other = u === movedVertex ? v : u;
        const originalLength = this.edgeLength(u, v);
        const newLength = this.distance(newPosition, this.vertices[other]);

        if (Math.abs(originalLength - newLength) > 0.01) {
          return false; // Edge length would change
        }
      }
    }
    return true; // All edge lengths preserved
  }

  edgeLength(u, v) {
    return this.distance(this.vertices[u], this.vertices[v]);
  }

  distance(p1, p2) {
    return Math.sqrt((p1.x - p2.x) ** 2 + (p1.y - p2.y) ** 2);
  }
}

