// Real-world rigidity applications
class RigidityApplications {
  // Structural engineering: Check truss stability
  checkTrussStability(joints, members) {
    const graph = {
      vertices: joints.map((_, i) => i),
      edges: members.map(m => [m.joint1, m.joint2])
    };

    const positions = {};
    joints.forEach((joint, i) => {
      positions[i] = { x: joint.x, y: joint.y };
    });

    const checker = new RigidityChecker();
    const result = checker.checkInfinitesimalRigidity(graph, positions);

    return {
      isStable: result.isRigid,
      rank: result.rank,
      recommendations: result.isRigid ?
        [] :
        this.suggestStabilization(graph, positions)
    };
  }

  suggestStabilization(graph, positions) {
    const suggestions = [];
    const n = graph.vertices.length;
    const m = graph.edges.length;
    const needed = 2 * n - 3;

    if (m < needed) {
      suggestions.push(
        `Add ${needed - m} more members to reach minimum rigidity`
      );
    }

    // Check for flexible substructures
    const checker = new LamansTheoremChecker();
    const lamanResult = checker.checkLamanConditions(graph);

    if (!lamanResult.condition2.satisfied) {
      suggestions.push(
        'Add cross-bracing to prevent flexible substructures'
      );
    }

    return suggestions;
  }

  // Robotics: Manipulator reachability
  checkManipulatorReachability(links, targetPosition) {
    // Model manipulator as kinematic chain
    const graph = this.buildManipulatorGraph(links.length);

    // Check if target is reachable
    const maxReach = links.reduce((sum, link) => sum + link.length, 0);
    const distance = Math.sqrt(
      targetPosition.x ** 2 + targetPosition.y ** 2
    );

    return {
      reachable: distance <= maxReach,
      maxReach: maxReach,
      currentDistance: distance
    };
  }

  buildManipulatorGraph(numLinks) {
    const vertices = Array.from({ length: numLinks + 1 }, (_, i) => i);
    const edges = Array.from({ length: numLinks }, (_, i) => [i, i + 1]);
    return { vertices, edges };
  }
}
